+    const results: IndexResult[] = [];
+    for (const [indexName, groupDocs] of grouped) {
+      const strategy = IndexingStrategy.forDocType(groupDocs[0].type);
+      const mapped = await Promise.all(groupDocs.map(async d => strategy.enrich(this.mapper.toElasticDoc(d, strategy.fieldMappings))));
