 @Injectable()
 export class CacheManager {
   private logger = new Logger(CacheManager.name);

-  async get<T>(key: string): Promise<T | null> {
-    const raw = await this.redis.get(key);
-    return raw ? JSON.parse(raw) : null;
+  async get<T>(key: string, policy?: CachePolicy): Promise<CacheResult<T>> {
+    const effectiveKey = policy?.namespace ? `${policy.namespace}:${key}` : key;
+    const raw = await this.redis.get(effectiveKey);
+    if (!raw) return { hit: false, data: null, stale: false };
+    const entry = this.serializer.deserialize<CacheEntry<T>>(raw);
+    const isStale = policy?.maxAge ? (Date.now() - entry.storedAt > policy.maxAge) : false;
+    if (isStale && policy?.staleWhileRevalidate) {
+      this.revalidateInBackground(effectiveKey, policy);
+      return { hit: true, data: entry.data, stale: true };
+    }
+    return { hit: true, data: entry.data, stale: false };
   }

-  async set<T>(key: string, value: T, ttl = 3600): Promise<void> {
-    await this.redis.set(key, JSON.stringify(value), 'EX', ttl);
+  async set<T>(key: string, value: T, policy?: CachePolicy): Promise<void> {
+    const effectiveKey = policy?.namespace ? `${policy.namespace}:${key}` : key;
+    const entry: CacheEntry<T> = { data: value, storedAt: Date.now(), version: policy?.version ?? 1 };
+    const serialized = this.serializer.serialize(entry);
+    const ttl = policy?.ttl ?? 3600;
+    await this.redis.set(effectiveKey, serialized, 'EX', ttl);
   }

-  async invalidate(key: string): Promise<void> {
-    await this.redis.del(key);
+  async invalidate(pattern: string, policy?: CachePolicy): Promise<number> {
+    const effectivePattern = policy?.namespace ? `${policy.namespace}:${pattern}` : pattern;
+    const keys = await this.redis.keys(effectivePattern);
+    if (keys.length === 0) return 0;
+    await this.redis.del(...keys);
+    return keys.length;
   }
